    private void ApplyInstanceOverrides()
    {
        if (_componentOverrides == null) return;
        if (TryGetComponentOverrideValue("$/2/0/0", "Text", out var componentOverrideValue0))
        {
            TabOneText.text = AsString(componentOverrideValue0);
        }
        if (TryGetComponentOverrideValue("$/2/5/0", "Text", out var componentOverrideValue1))
        {
            TabFooterText.text = AsString(componentOverrideValue1);
        }
        if (TryGetComponentOverrideValue("$/3/0", "Text", out var componentOverrideValue2))
        {
            ListHeader.text = AsString(componentOverrideValue2);
        }
        if (TryGetComponentOverrideValue("$/3/1", "Text", out var componentOverrideValue3))
        {
            CategoryHeader.text = AsString(componentOverrideValue3);
        }
        if (TryGetComponentOverrideValue("$/3/2/0", "Text", out var componentOverrideValue4))
        {
            SelectedQuestTitle.text = AsString(componentOverrideValue4);
        }
        if (TryGetComponentOverrideValue("$/3/2/1", "Text", out var componentOverrideValue5))
        {
